import React from 'react'
import ReactApexChart from 'react-apexcharts'
import ApexCharts from 'apexcharts'
import './styles.css'

// Deterministic 30-day dashboard data (no randomness, stable demo).
var LV_START = new Date('2024-03-01').getTime()
var LV_DAY = 86400000
function ordersData() {
  var out = []
  for (var i = 0; i < 30; i++) {
    var v = 60 + 30 * Math.sin(i / 3.3) + 14 * Math.sin(i / 1.7) + i * 0.6
    out.push([LV_START + i * LV_DAY, Math.round(v)])
  }
  return out
}
function valueData() {
  var out = []
  for (var i = 0; i < 30; i++) {
    // average order value, loosely anti-correlated with volume
    var v = 120 - 22 * Math.sin(i / 3.3) + 10 * Math.cos(i / 2.1)
    out.push([LV_START + i * LV_DAY, Math.round(v)])
  }
  return out
}

// Shared by the vanilla-js, React and Vue builds.
function fmt(ts) {
  return new Date(ts).toISOString().slice(0, 10)
}

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [{ name: 'Orders', data: ordersData() }],
    options: {
      chart: {
        id: 'orders',
        height: 250,
        type: 'bar',
        group: 'sales',
        fontFamily: 'Helvetica, Arial, sans-serif',
        animations: { enabled: false },
        link: { enabled: true, dimOpacity: 0.16 },
        selection: { enabled: true },
        toolbar: {
          autoSelected: 'selection',
          tools: {
            selection: true,
            zoom: false,
            pan: false,
            reset: false,
            download: false,
          },
        },
      },
      colors: ['#6366f1'],
      plotOptions: { bar: { columnWidth: '60%', borderRadius: 2 } },
      dataLabels: { enabled: false },
      title: { text: 'Daily orders (brush a range here)', align: 'left' },
      xaxis: { type: 'datetime' },
    },
    series1: [{ name: 'Avg value', data: valueData() }],
    options1: {
      chart: {
        id: 'value',
        height: 250,
        type: 'scatter',
        group: 'sales',
        fontFamily: 'Helvetica, Arial, sans-serif',
        animations: { enabled: false },
        link: { enabled: true, dimOpacity: 0.16 },
        zoom: { enabled: false },
        toolbar: { show: false },
      },
      colors: ['#0ea5e9'],
      markers: { size: 6 },
      title: { text: 'Avg order value (crossfiltered)', align: 'left' },
      xaxis: { type: 'datetime' },
      yaxis: {
        labels: {
          formatter: function (v) {
            return '$' + Math.round(v)
          },
        },
      },
    },
  })

  React.useEffect(() => {
    // The react-apexcharts wrapper owns the render, so reach the brush-source
    // chart ('orders') by its chart.id. Poll until it exists, then wire the same
    // crossfilter readout + clear button the vanilla build does. (fmt lives in the
    // shared head script.) The link feature drives the chart instances directly,
    // so no React state changes and the charts are not re-rendered under it.
    let chart
    const readout = document.getElementById('readout')
    const onClear = () => {
      if (chart) chart.clearCrossfilter()
      if (readout) readout.textContent = 'Cleared'
    }
    const onCrossFilter = (c, opts) => {
      readout.textContent =
        'Filtered: ' + fmt(opts.xaxis.min) + ' to ' + fmt(opts.xaxis.max)
    }

    const timer = window.setInterval(() => {
      chart = ApexCharts.getChartByID('orders')
      if (!chart) return
      window.clearInterval(timer)
      chart.addEventListener('crossFilter', onCrossFilter)
      document.getElementById('clear').addEventListener('click', onClear)
    }, 50)

    return () => {
      window.clearInterval(timer)
      const btn = document.getElementById('clear')
      if (btn) btn.removeEventListener('click', onClear)
    }
  }, [])

  return (
    <div>
      <div className="panel">
        <div className="bar">
          <button id="clear">Clear crossfilter</button>
          <span className="readout" id="readout">
            Drag a date range on the top chart to crossfilter both
          </span>
        </div>
      </div>

      <div className="wrap">
        <div id="chart">
          <ReactApexChart
            options={state.options}
            series={state.series}
            type="bar"
            height={250}
          />
        </div>
      </div>
      <div className="wrap">
        <div id="chart2">
          <ReactApexChart
            options={state.options1}
            series={state.series1}
            type="scatter"
            height={250}
          />
        </div>
      </div>

      <div className="panel">
        <div className="note">
          Both charts share <code>chart.group: 'sales'</code> and opt in with
          <code>chart.link.enabled</code>. The top chart also has
          <code>chart.selection.enabled</code>, so dragging a date range on it
          dims every data point (in both charts) whose date falls outside the
          range, in place, with no re-render and no axis change. Slide or resize
          the selection box (or draw a new one) to update the filter live;
          <b>Clear crossfilter</b> (or <code>chart.clearCrossfilter()</code>)
          restores. Needs the <code>link</code> feature. Highlight mode works on
          discrete marks (columns, scatter); a continuous line path is not
          dimmed per segment.
        </div>
      </div>
    </div>
  )
}

export default ApexChart

.wrap {
  max-width: 820px;
  margin: 12px auto;
}
